import React, { useEffect, useState } from "react";
import api from "../../api/axios";
import "../admin/Admin.css";

export default function TeacherStudents() {
  const [classes, setClasses] = useState([]);
  const [selectedClass, setSelectedClass] = useState(null);
  const [students, setStudents] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get("/teacher/classes")
      .then(r => { const data = r.data.data || []; setClasses(data); if (data.length > 0) { setSelectedClass(data[0]); loadStudents(data[0].id); } })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const loadStudents = async (classId) => {
    const r = await api.get(`/teacher/classes/${classId}/students`).catch(() => ({ data: { data: [] } }));
    setStudents(r.data.data || []);
  };

  const handleClassChange = (cls) => { setSelectedClass(cls); loadStudents(cls.id); };

  return (
    <div className="admin-page fade-in">
      <div className="page-header">
        <h1>Học viên</h1>
        <p>Xem tiến độ học tập của học viên</p>
      </div>

      <div style={{ display: "flex", gap: 8, marginBottom: 16, flexWrap: "wrap" }}>
        {classes.map(c => (
          <button key={c.id} className={`btn ${selectedClass?.id === c.id ? "btn-primary" : "btn-ghost"}`}
            onClick={() => handleClassChange(c)}>{c.name}</button>
        ))}
      </div>

      <div className="table-wrapper">
        {loading ? <div className="page-loading"><div className="spinner" /></div> : (
          <table className="data-table">
            <thead><tr><th>Học viên</th><th>Trạng thái</th><th>Tiến độ</th><th>Ngày đăng ký</th></tr></thead>
            <tbody>
              {students.length === 0
                ? <tr><td colSpan={4} className="empty-state"><p>Chưa có học viên</p></td></tr>
                : students.map(s => (
                  <tr key={s.id}>
                    <td>ID: {s.userId}</td>
                    <td><span className={`badge ${s.status === "enrolled" ? "badge-green" : "badge-yellow"}`}>{s.status}</span></td>
                    <td>
                      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                        <div style={{ flex: 1, height: 6, background: "var(--gray-100)", borderRadius: 3, overflow: "hidden" }}>
                          <div style={{ height: "100%", width: `${s.progress || 0}%`, background: "var(--primary)", borderRadius: 3 }} />
                        </div>
                        <span style={{ fontSize: "0.78rem", color: "var(--gray-500)", flexShrink: 0 }}>{s.progress || 0}%</span>
                      </div>
                    </td>
                    <td style={{ fontSize: "0.82rem", color: "var(--gray-500)" }}>
                      {s.enrollDate ? new Date(s.enrollDate).toLocaleDateString("vi-VN") : "—"}
                    </td>
                  </tr>
                ))
              }
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}
